class TestRegisterLookupMixin:
    def test_get_lookup(self):
        class TestClass(RegisterLookupMixin):
            class_lookups = {'test': str}
        assert TestClass._get_lookup('test') == str
        assert TestClass._get_lookup('nonexistent') is None

    def test_get_lookups_cached(self):
        class TestClass(RegisterLookupMixin):
            class_lookups = {'test': str}
        with patch.object(TestClass, 'merge_dicts') as mock_merge:
            mock_merge.return_value = {'test': str}
            result = TestClass.get_lookups()
            assert result == {'test': str}
            mock_merge.assert_called_once()
            # Second call should use cache
            TestClass.get_lookups.cache_clear()
            TestClass.get_lookups()
            assert mock_merge.call_count == 2

    def test_register_lookup(self):
        class TestClass(RegisterLookupMixin):
            pass
        TestClass.register_lookup(str, 'test')
        assert TestClass.class_lookups['test'] == str

    def test_unregister_lookup(self):
        class TestClass(RegisterLookupMixin):
            class_lookups = {'test': str}
        TestClass._unregister_lookup(str, 'test')
        assert 'test' not in TestClass.class_lookups

    def test_merge_dicts(self):
        dicts = [{'a': 1}, {'b': 2}, {'a': 3}]
        result = RegisterLookupMixin.merge_dicts(dicts)
        assert result == {'a': 1, 'b': 2}

